const normalize = (str) => str.toLowerCase().split('').sort().join();
const sameWord = (word, candidate) =>
  word.toLowerCase() === candidate.toLowerCase();
const isAnagram = (word, candidate) => normalize(word) === normalize(candidate);

export const findAnagrams = (subject, candidates) => {
  const wordsCopy = Array.isArray(candidates) ? candidates : [...candidates];
  return wordsCopy.filter(
    (candidate) =>
      !sameWord(subject, candidate) && isAnagram(subject, candidate),
  );
};

export const steps = (n) => {
  if (n <= 0) {
    throw new Error('Only positive integers are allowed');
  }

  const iterate = (number, step) => {
    if (number === 1) {
      return step;
    }

    return number % 2 === 0
      ? iterate(number / 2, step + 1)
      : iterate(3 * number + 1, step + 1);
  };
  return iterate(n, 0);
};

export const score = (x, y) => {
  // Check for NaN
  if (Number.isNaN(Number(x)) || Number.isNaN(Number(y))) return null;

  // Use euclidean distance
  const distanceToDart = Math.sqrt(x * x + y * y);

  // Define points for each section of the target
  if (distanceToDart > 10) return 0;
  if (distanceToDart > 5) return 1;
  if (distanceToDart > 1) return 5;
  return 10;
};

export class Squares {
  constructor(max) {
    this.max = max;
  }

  get squareOfSum() {
    let sum = 0;
    for (let x = 1; x <= this.max; x += 1) {
      sum += x;
    }
    return sum * sum;
  }

  get sumOfSquares() {
    let sum = 0;
    for (let x = 1; x <= this.max; x += 1) {
      sum += x * x;
    }
    return sum;
  }

  get difference() {
    return this.squareOfSum - this.sumOfSquares;
  }
}

export class HighScores {
  constructor(scores) {
    this.scores = scores;
  }

  get latest() {
    return this.scores[this.scores.length - 1];
  }

  get personalBest() {
    return Math.max(...this.scores);
  }

  get personalTopThree() {
    return [...this.scores]
      .sort((a, b) => a - b)
      .reverse()
      .slice(0, 3);
  }
}

export const isIsogram = (string) => {
  const stringNoSpaceOrHyphen = string.replace(/ |-/g, '');
  const uniqueLetters = stringNoSpaceOrHyphen
    .toLowerCase()
    .split('')
    .filter((element, index, self) => self.indexOf(element) === index);
  return uniqueLetters.length === stringNoSpaceOrHyphen.length;
};

