export const isLeap = (year) =>
  year % 400 === 0 || (year % 4 === 0 && year % 100 !== 0);

export const isPaired = (input) => {
  const brackets = input.replace(/[^{(\[\])}]/g, ''); //eslint-disable-line
  const bracketsAreMatching = (leftBracket, rightBracket) =>
    (leftBracket === '(' && rightBracket === ')') ||
    (leftBracket === '[' && rightBracket === ']') ||
    (leftBracket === '{' && rightBracket === '}');

  let arr = [];
  for (let letter of brackets) {
    if (arr.length >= 1) {
      const lastBracket = arr[arr.length - 1];
      if (bracketsAreMatching(lastBracket, letter)) {
        arr.pop();
      } else {
        arr.push(letter);
      }
    } else {
      arr.push(letter);
    }
  }
  return arr.length === 0;
};

const notAlpha = /[^a-z]+/gi;
const alphaLength = 26;

export const isPangram = (candidate) => {
  const cleaned = candidate.replace(notAlpha, '').toLowerCase();
  const sortedSet = new Set([...cleaned].sort());
  return sortedSet.size === alphaLength;
};

/**
 * Calculate all the divisors for a given number.
 * @param {number} number - natural number.
 * @returns {array} that contains the divisors for a given number excluding the number itself.
 */
function getDivisors(number) {
  const divs = [];

  // Accepts only natural numbers greater than 1.
  if (number <= 1) {
    return divs;
  }

  // 1 always divides everyone!
  divs.push(1);

  // Calculate the divisors up the the half of the number + 1
  for (let i = 2; i <= number / 2; i += 1) {
    if (number % i === 0) {
      divs.push(i);
    }
  }

  return divs;
}

/**
 * Classify a given number as perfect, abundant or deficient.
 * @param {number} - number to be classified. Note: if the number is equal or smaller than 0,
 * then returns an error: Classification is only possible for natural numbers.
 * @returns {string} - string that contains the classification (perfect, abundant or deficient).
 */
export const classify = (number) => {
  // Check if the input is valid
  if (number <= 0) {
    throw new Error('Classification is only possible for natural numbers.');
  }

  // Factorize the current number.
  const divsArray = getDivisors(number);

  // Sum the factors.
  const sum = divsArray.reduce((partialSum, div) => partialSum + div, 0);

  // Check if the number is perfect/abundant/deficient
  if (sum === number) return 'perfect';
  if (sum > number) return 'abundant';
  return 'deficient';
};

export const clean = (number) => {
  if (/[a-zA-Z]/.test(number)) {
    throw new Error('Letters not permitted');
  } else if (/[@:!]/.test(number)) {
    throw new Error('Punctuations not permitted');
  }

  let strippedNumber = number.replace(/\D/g, '');
  const numberLength = strippedNumber.length;

  if (numberLength === 11) {
    if (strippedNumber.substring(0, 1) !== '1') {
      throw new Error('11 digits must start with 1');
    } else {
      strippedNumber = strippedNumber.substring(1);
    }
  }

  if (numberLength < 10) {
    throw new Error('Must not be fewer than 10 digits');
  }

  if (numberLength > 11) {
    throw new Error('Must not be greater than 11 digits');
  }

  if (strippedNumber.substring(0, 1) === '0') {
    throw new Error('Area code cannot start with zero');
  } else if (strippedNumber.substring(0, 1) === '1') {
    throw new Error('Area code cannot start with one');
  }

  if (strippedNumber.substring(3, 4) === '0') {
    throw new Error('Exchange code cannot start with zero');
  } else if (strippedNumber.substring(3, 4) === '1') {
    throw new Error('Exchange code cannot start with one');
  }

  return strippedNumber;
};

export const encode = (msg, rails) => {
  let stringRails = Array(rails).fill('');
  cycleRails(msg, rails).forEach((cycle, index) => {
    stringRails[cycle] += msg[index];
  });
  return stringRails.join('');
};

export const decode = (msg, rails) => {
  const cycles = cycleRails(msg, rails);
  let stringRails = Array(rails).fill('');
  cycleRails(msg, rails).forEach((cycle) => {
    for (let j = 0; j < rails; j++) {
      stringRails[j] += cycle === j ? '?' : '.';
    }
  });
  let msgIndex = 0;
  stringRails.forEach((rail, index) => {
    let newRail = '';
    rail.split('').forEach((char) => {
      if (char === '?') {
        newRail += msg[msgIndex];
        msgIndex++;
      } else {
        newRail += '.';
      }
    });
    stringRails[index] = newRail;
  });
  return cycles.reduce(
    (str, cycle, index) => str + stringRails[cycle][index],
    '',
  );
};

const cycleRails = (msg, rails) => {
  let currentRail = 0;
  let isIncreasing = true;
  let cycles = [];
  for (let i = 0; i < msg.length; i++) {
    cycles.push(currentRail);
    currentRail = isIncreasing ? currentRail + 1 : currentRail - 1;
    if (currentRail < 0) {
      currentRail = 1;
      isIncreasing = true;
    } else if (currentRail === rails) {
      currentRail = rails - 2;
      isIncreasing = false;
    }
  }
  return cycles;
};

export const convert = (n) => {
  let result = '';
  if (n % 3 === 0) {
    result += 'Pling';
  }
  if (n % 5 === 0) {
    result += 'Plang';
  }
  if (n % 7 === 0) {
    result += 'Plong';
  }
  return result === '' ? n.toString() : result;
};

export const reverseString = (string) => {
  let revString = '';
  let characters = Array.from(
    new Intl.Segmenter().segment(String(string)),
    (x) => x.segment,
  );
  for (let i = characters.length - 1; i >= 0; i--) {
    revString += characters[i];
  }
  return revString;
};

