export function toRoman(number) {
  let result = '';
  let remainingNumber = number;
  const mappings = [
    { arabic: 1000, roman: 'M' },
    { arabic: 900, roman: 'CM' },
    { arabic: 500, roman: 'D' },
    { arabic: 400, roman: 'CD' },
    { arabic: 100, roman: 'C' },
    { arabic: 90, roman: 'XC' },
    { arabic: 50, roman: 'L' },
    { arabic: 40, roman: 'XL' },
    { arabic: 10, roman: 'X' },
    { arabic: 9, roman: 'IX' },
    { arabic: 5, roman: 'V' },
    { arabic: 4, roman: 'IV' },
    { arabic: 1, roman: 'I' },
  ];

  mappings.forEach((mapping) => {
    while (remainingNumber >= mapping.arabic) {
      result += mapping.roman;
      remainingNumber -= mapping.arabic;
    }
  });

  return result;
}

export const encode = (plainText) => {
  const consecutiveChars = /([\w\s])\1*/g;
  return plainText.replace(consecutiveChars, (match) =>
    match.length > 1 ? match.length + match[0] : match[0],
  );
};

export const decode = (encodedText) => {
  const countAndChar = /(\d+)(\w|\s)/g;
  return encodedText.replace(countAndChar, (match, repeats, char) =>
    new Array(Number(repeats) + 1).join(char),
  );
};

export class Series {
  constructor(numberString) {
    if (!numberString) {
      throw new Error('series cannot be empty');
    }

    this.numberString = numberString;
    this.digits = this.getDigits();
  }

  getDigits() {
    return [...this.numberString].map((digit) => parseInt(digit, 10));
  }

  slices(sliceSize) {
    const result = [];
    let slice = [];

    if (sliceSize < 0) {
      throw new Error('slice length cannot be negative');
    }

    if (sliceSize === 0) {
      throw new Error('slice length cannot be zero');
    }

    if (sliceSize > this.digits.length) {
      throw new Error('slice length cannot be greater than series length');
    }

    for (let i = 0; i < this.digits.length - sliceSize + 1; i += 1) {
      for (let j = 0; j < sliceSize; j += 1) {
        slice.push(this.digits[i + j]);
      }
      result.push(slice);
      slice = [];
    }

    return result;
  }
}

function trimTrailingUndefined(array) {
  const trailingUndefinedCount = [...array]
    .reverse()
    .findIndex((x) => x !== undefined);
  return array.slice(0, array.length - trailingUndefinedCount);
}

export function transpose(input) {
  const maxCol = Math.max(0, ...input.map((row) => row.length));
  return [...Array(maxCol).keys()].map((col) =>
    trimTrailingUndefined(input.map((_v, row) => input[row][col]))
      .map((charOrUndefined) => charOrUndefined || ' ')
      .join(''),
  );
}

