export function countNucleotides(strand) {
  if (strand.replace(/A|C|G|T/g, '').length) {
    throw new Error('Invalid nucleotide in strand');
  }

  return `${count(strand, 'A')} ${count(strand, 'C')} ${count(
    strand,
    'G',
  )} ${count(strand, 'T')}`;
}

const VOWEL_SOUND_REGEXP = /^([aeiou]|xr|yt)/;
const CONSONANT_SOUND_REGEXP =
  /^([^aeiou]+(?=y)|[^aeiou]?qu|[^aeiou]+)([a-z]+)/;

function translateWord(word) {
  if (VOWEL_SOUND_REGEXP.test(word)) {
    return `${word}ay`;
  }

  const newWord = word.replace(CONSONANT_SOUND_REGEXP, '$2$1');
  return `${newWord}ay`;
}

export const translate = (english) => {
  return english.split(' ').map(translateWord).join(' ');
};

const W = 8;
const H = 8;
const STARTING = { black: [0, 3], white: [7, 3] };

function invalidPosition({ white, black }) {
  if (white[0] < 0 || white[0] >= H || white[1] < 0 || white[1] >= W) {
    return true;
  }

  if (black[0] < 0 || black[0] >= H || black[1] < 0 || black[1] >= W) {
    return true;
  }

  return false;
}

function samePosition({ white, black }) {
  return white[0] === black[0] && white[1] === black[1];
}

function constructBoard() {
  return new Array(W * H).fill('_');
}

function placePieces(self) {
  const board = self.board;
  const [blackRow, blackColumn] = self.black;
  const [whiteRow, whiteColumn] = self.white;

  board[blackRow * W + blackColumn] = 'B';
  board[whiteRow * W + whiteColumn] = 'W';
}

export class QueenAttack {
  constructor(params = {}) {
    params = { ...STARTING, ...params };
    if (invalidPosition(params)) {
      throw new Error('Queen must be placed on the board');
    }

    if (samePosition(params)) {
      throw new Error('Queens cannot share the same space');
    }

    this.black = params.black;
    this.white = params.white;
    this.board = constructBoard();

    placePieces(this);

    return this;
  }

  get canAttack() {
    // Same row or column
    if (this.black[0] === this.white[0] || this.black[1] === this.white[1]) {
      return true;
    }

    // Diagonally
    return (
      Math.abs(this.black[0] - this.white[0]) ===
      Math.abs(this.black[1] - this.white[1])
    );
  }

  toString() {
    return Array.from({ length: H }, (_, row) =>
      this.board.slice(row * H, row * H + W).join(' '),
    ).join('\n');
  }
}

export const saddlePoints = (matrix) => {
  const maximumRowValues = [];
  const minimumColumnValues = [];

  for (let i = 0; i <= matrix.length - 1; i++) {
    const maximumRowValue = Math.max(...matrix[i]);
    maximumRowValues.push(maximumRowValue);
  }

  for (let i = 0; i <= matrix[0].length - 1; i++) {
    let minimumColumnValue = Number.MAX_VALUE;
    for (let j = 0; j <= matrix.length - 1; j++) {
      minimumColumnValue = Math.min(minimumColumnValue, matrix[j][i]);
    }
    minimumColumnValues.push(minimumColumnValue);
  }

  const resultPoints = [];
  for (let i = 0; i < maximumRowValues.length; i++) {
    for (let j = 0; j < minimumColumnValues.length; j++) {
      if (maximumRowValues[i] === minimumColumnValues[j]) {
        resultPoints.push({ row: i + 1, column: j + 1 });
      }
    }
  }

  return resultPoints;
};

export const spiralMatrix = (size) => {
  const spiral = Array(size)
    .fill()
    .map(() => Array(0));

  const totalNumbers = size ** 2;
  let currentNumber = 1;
  let topLeft = 0;
  let bottomRight = size - 1;

  while (currentNumber <= totalNumbers) {
    for (let x = topLeft; x <= bottomRight; x += 1) {
      spiral[topLeft][x] = currentNumber;
      currentNumber += 1;
    }

    for (let y = topLeft + 1; y <= bottomRight; y += 1) {
      spiral[y][bottomRight] = currentNumber;
      currentNumber += 1;
    }

    for (let x = bottomRight - 1; x >= topLeft; x -= 1) {
      spiral[bottomRight][x] = currentNumber;
      currentNumber += 1;
    }

    for (let y = bottomRight - 1; y >= topLeft + 1; y -= 1) {
      spiral[y][topLeft] = currentNumber;
      currentNumber += 1;
    }

    topLeft += 1;
    bottomRight -= 1;
  }

  return spiral;
};

export const sum = (multiples, limit) => {
  let result = 0;
  for (let i = 1; i < limit; i++) {
    if (multiples.some((multiple) => i % multiple === 0)) {
      result += i;
    }
  }
  return result;
};

const ALPHABET = 'abcdefghijklmnopqrstuvwxyz';

export const encode = (message) => {
  const encodedMessage = [...message.toLowerCase().replace(/[ .,]/g, '')]
    .map((char) => {
      if (ALPHABET.includes(char)) {
        return ALPHABET[ALPHABET.length - 1 - ALPHABET.indexOf(char)];
      }
      return char;
    })
    .join('');
  return encodedMessage.match(/.{1,5}/g).join(' ');
};

export const decode = (message) => {
  return encode(message).replace(/ /g, '');
};

export const find = (array, element) => {
  let start = 0;
  let end = array.length - 1;
  let middle;
  while (start <= end) {
    middle = Math.floor((start + end) / 2);
    if (element === array[middle]) {
      return middle;
    } else if (element < array[middle]) {
      end = middle - 1;
    } else if (element > array[middle]) {
      start = middle + 1;
    }
  }
  throw new Error('Value not in array');
};

const MINE = '*';

const DELTAS = [
  [-1, -1],
  [-1, 0],
  [-1, 1],
  [1, 1],
  [1, 0],
  [1, -1],
  [0, 1],
  [0, -1],
];

function adjacentSquareIsOnBoard(board, x, d) {
  return board[x + d[0]];
}

function adjacentSquareHasMine(board, x, y, d) {
  return board[x + d[0]][y + d[1]] === MINE;
}

function countAdjacentMines(board, x, y) {
  return DELTAS.filter((d) => adjacentSquareIsOnBoard(board, x, d)).filter(
    (d) => adjacentSquareHasMine(board, x, y, d),
  ).length;
}

function cellToMineOrCount(cell, inputBoard, x, y) {
  if (cell === MINE) {
    return MINE;
  }

  return countAdjacentMines(inputBoard, x, y) || ' ';
}

function stringify(board) {
  return board.map((row) => row.join(''));
}

function noDataPresent(rows) {
  return rows.length === 0 || rows[0].length === 0;
}

export function annotate(rows) {
  if (noDataPresent(rows)) {
    return rows;
  }

  const inputBoard = rows.map((row) => [...row]);

  return stringify(
    inputBoard.map((row, x) =>
      [...row].map((cell, y) => cellToMineOrCount(cell, inputBoard, x, y)),
    ),
  );
}
